import React from "react";
import DualRangeSlider from "./DualRangeSlider";
import { HEIGHT_RANGE_OPTIONS } from "@/lib/constants";

const getMinMaxHeight = () => {
  const allValues = HEIGHT_RANGE_OPTIONS.flatMap((opt) =>
    opt.value.split("-").map((v) => Number(v)),
  ).filter((n) => Number.isFinite(n));
  return {
    min: Math.min(...allValues),
    max: Math.max(...allValues),
  };
};

const HeightFilter = ({ value, onChange }) => {
  const { min, max } = getMinMaxHeight();
  const current = value || [min, max];

  return (
    <div className="px-6 mt-4">
      <div className="flex justify-between mb-8">
        <Badge label="From" value={`${current[0]} cm`} />
        <Badge label="To" value={`${current[1]} cm`} />
      </div>
      <DualRangeSlider min={min} max={max} value={current} onChange={onChange} />
      <p className="text-center text-xs text-gray-400 mt-6">Select height range</p>
    </div>
  );
};

const Badge = ({ label, value }) => (
  <div className="flex flex-col items-center">
    <span className="text-[10px] text-gray-400 font-bold uppercase mb-1">{label}</span>
    <div className="bg-[#FFFBF7] border border-[#E8DCC6] text-[#4A2C2A] font-bold py-2 px-4 rounded-lg min-w-[90px] text-center">{value}</div>
  </div>
);

export default HeightFilter;
